import os
import json

ALLOWED_DIRECTORY = "/var/www/files"

def safely_read_file(request_payload):
    """Read files safely with path traversal protection."""
    try:
        data = json.loads(request_payload)
        filename = data.get("filename", "")
        request_id = data.get("request_id")

        # Normalize path and ensure it's within allowed directory
        requested_path = os.path.normpath(os.path.join(ALLOWED_DIRECTORY, filename))
        allowed_path = os.path.normpath(ALLOWED_DIRECTORY)

        if not requested_path.startswith(allowed_path):
            return {"status": "error", "message": "Access denied"}

        if not os.path.exists(requested_path):
            return {"status": "error", "message": "File not found"}

        with open(requested_path, 'r') as f:
            content = f.read()

        return {"status": "success", "content": content}
    except Exception as e:
        return {"status": "error", "message": str(e)}
